def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Fill in values for options whose default depends on the
    resolved value of other options (see ``Option``'s dict-based
    ``default``). This runs after the command line, environment
    variables, and configuration files have all been processed, and
    only touches options whose value still comes from ``DEFAULT``.

    .. versionadded:: 8.3.0
    """
    opt_to_param: dict[str, Option] = {}

    for param in self.get_params(ctx):
        if isinstance(param, Option):
            for opt in (*param.opts, *param.secondary_opts):
                opt_to_param[opt] = param

    for param in self.get_params(ctx):
        if not isinstance(param, Option) or param._dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for opt_name, mapping in param._dynamic_default.items():
            source = opt_to_param.get(opt_name)

            if source is None:
                continue

            key = str(ctx.params.get(source.name))  # type: ignore[arg-type]

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = param.type_cast_value(ctx, resolved)  # type: ignore[arg-type]

